glossary.json:
{
  "terms": [
    {
      "term": "Anschluss",
      "definition": "Literally 'connection' or 'joining'. The annexation of Austria into Nazi Germany on 12 March 1938. The term refers to the political union that had been forbidden by the Treaty of Versailles. A plebiscite conducted under occupation produced a reported 99.73% approval.",
      "origin": "German: anschließen — to connect, join"
    },
    {
      "term": "Blitzkrieg",
      "definition": "Literally 'lightning war'. The combined-arms military strategy using armoured vehicles, motorised infantry, and air support to overwhelm and penetrate enemy defences before they could reorganise. Applied effectively in Poland (1939) and France (1940). The term was used more by Allied observers and journalists than by German commanders themselves.",
      "origin": "German: Blitz (lightning) + Krieg (war)"
    },
    {
      "term": "Deutsche Arbeitsfront (DAF)",
      "definition": "The German Labour Front, established 10 May 1933 after the Nazis dissolved all trade unions. Led by Robert Ley, it enrolled over 25 million workers by 1939 — the largest mass organisation in the Third Reich. The DAF ran the Kraft durch Freude (Strength through Joy) leisure programme, which provided subsidised holidays, cultural events, and the Volkswagen savings scheme.",
      "origin": "German: Deutsche Arbeitsfront — German Labour Front"
    },
    {
      "term": "Einsatzgruppen",
      "definition": "SS mobile killing units that followed the Wehrmacht into occupied Soviet territories from 1941. They were responsible for the massacre of approximately 1.5–2 million Jews, Roma, Soviet officials, and others — primarily by mass shooting into pits. The largest single operation, Babi Yar (29–30 September 1941, near Kyiv), killed 33,771 Jews in two days.",
      "origin": "German: Einsatz (deployment, operation) + Gruppe (group)"
    },
    {
      "term": "Enabling Act (Ermächtigungsgesetz)",
      "definition": "The law passed by the Reichstag on 23 March 1933 that gave Hitler's cabinet the power to enact laws without Reichstag approval for four years. Passed with Centre Party support after Communist deputies were arrested or absent. It effectively ended the Weimar Republic and transferred legislative power to Hitler. Renewed in 1937 and 1939; superseded by Hitler's wartime powers.",
      "origin": "German: ermächtigen — to empower, authorise"
    },
    {
      "term": "Final Solution (Endlösung)",
      "definition": "The Nazi regime's plan for the systematic genocide of the Jews of Europe. The phrase 'final solution of the Jewish question' (Endlösung der Judenfrage) was used at the Wannsee Conference of January 1942, which coordinated the industrial-scale murder. The Holocaust resulted in the death of approximately six million Jews — two-thirds of European Jewry — in shooting operations, gas vans, and purpose-built extermination camps.",
      "origin": "German: Endlösung — final solution, final resolution"
    },
    {
      "term": "Führer",
      "definition": "German for 'leader'. Hitler's official title from August 1934, combining the offices of Chancellor and President after Hindenburg's death. It carried connotations of an absolute, messianic, quasi-divine leadership, distinct from all normal political authority. Germans were required to use 'Heil Hitler' as a greeting from 1933.",
      "origin": "German: führen — to lead"
    },
    {
      "term": "Gauleiter",
      "definition": "The regional NSDAP leaders, each responsible for one of Germany's 43 Gaue (districts). Gauleiters combined party authority with growing state power (often serving as Reich Governors), controlled regional economic and military resources, and wielded enormous local power. Some, like Josef Grünpfner of East Prussia (Erich Koch) or Fritz Sauckel of Thuringia, became de facto regional dictators, particularly in occupied eastern territories.",
      "origin": "German: Gau (district) + Leiter (leader)"
    },
    {
      "term": "Gestapo (Geheime Staatspolizei)",
      "definition": "The Secret State Police of Nazi Germany. Founded in Prussia by Göring in April 1933, transferred to SS control under Heydrich in 1934. Operated without judicial oversight, using surveillance, denunciations, interrogation, and extra-judicial detention to suppress political opposition. A criminal organisation as determined at Nuremberg. Contrary to popular image, the Gestapo was relatively small (roughly 32,000 officers for all of Germany in 1944) and depended extensively on civilian denunciations.",
      "origin": "German acronym: Geheime Staatspolizei — Secret State Police"
    },
    {
      "term": "Gleichschaltung",
      "definition": "Literally 'coordination' or 'bringing into line'. The process by which the Nazis brought all German institutions — political parties, trade unions, press, judiciary, universities, professional bodies, cultural organisations — under party control between 1933 and 1934. The term comes from electrical engineering, describing the alignment of circuits.",
      "origin": "German: gleich (same, equal) + schalten (to switch, connect)"
    },
    {
      "term": "Holocaust (Shoah)",
      "definition": "The systematic, state-sponsored persecution and murder of six million Jews by the Nazi regime and its collaborators between 1933 and 1945. The term 'Holocaust' (from Greek: whole burned offering) became predominant in English from the 1960s. The Hebrew term 'Shoah' (catastrophe) is preferred by many Jewish communities. The murder also encompassed approximately 250,000–500,000 Roma, 275,000+ disabled persons, 1.8–3 million Soviet POWs, and hundreds of thousands of political prisoners and others.",
      "origin": "Greek: holókaustos — wholly burned; Hebrew equivalent: Shoah (catastrophe)"
    },
    {
      "term": "Kristallnacht",
      "definition": "Literally 'Night of Crystal' or 'Night of Broken Glass'. The coordinated nationwide pogrom against Jews on 9–10 November 1938, ordered by Goebbels with Hitler's approval following the assassination of German diplomat Ernst vom Rath in Paris by Herschel Grynszpan. Over 7,500 Jewish businesses destroyed, ~1,400 synagogues burned or damaged, 91 Jews killed (official figure; actual deaths higher), 30,000 arrested and sent to camps. Jews were subsequently ordered to pay a 1-billion-Reichsmark 'atonement fine'.",
      "origin": "German: Kristall (crystal, glass) + Nacht (night)"
    },
    {
      "term": "Kraft durch Freude (KdF)",
      "definition": "Literally 'Strength through Joy'. The DAF's leisure organisation, designed to provide subsidised recreation for German workers — cruises, theatre, concerts, sports, and the famous KdF-Wagen (Volkswagen) savings scheme. It was also an instrument of mass surveillance, monitoring workers' political reliability. By 1938, KdF organised more leisure travel than any organisation in the world.",
      "origin": "German: Kraft (strength) + durch (through) + Freude (joy)"
    },
    {
      "term": "Lebensraum",
      "definition": "Literally 'living space'. The geopolitical concept that Germany required vast territories to the east (primarily the Soviet Union and Poland) for German agricultural settlement, resource exploitation, and demographic expansion. Developed by geographer Friedrich Ratzel in the 1890s; adopted and radicalised by Hitler, who combined it with antisemitism (Bolshevism as Jewish conspiracy) and Social Darwinism. The concept provided the ideological framework for Operation Barbarossa and the murderous occupation policies in the east.",
      "origin": "German: Leben (life) + Raum (space, room)"
    },
    {
      "term": "Mein Kampf",
      "definition": "Hitler's autobiographical political manifesto, dictated to Rudolf Hess during his imprisonment at Landsberg following the failed Beer Hall Putsch. Published in two volumes: vol. 1 (1925) and vol. 2 (1926). It outlined his life story, his ideology (antisemitism, German nationalism, anti-Marxism, Lebensraum), and his strategic vision. By 1945, 12.4 million copies had been distributed — given free to every German newlywed couple and soldier. Despite clear statements of intent, Allied leaders did not take its contents seriously before 1939.",
      "origin": "German: Mein (my) + Kampf (struggle, fight)"
    },
    {
      "term": "Night of the Long Knives (Nacht der langen Messer)",
      "definition": "The purge of 30 June–2 July 1934 in which Hitler ordered the murder of SA leadership and other perceived threats. At least 85 killed, including SA Chief of Staff Ernst Röhm, former Chancellor Kurt von Schleicher, and Gregor Strasser. The killings were retroactively legalised as 'state self-defence'. The purge eliminated the SA as a political force, confirmed SS supremacy, and secured the Wehrmacht's cooperation with the regime — in exchange for the oath of personal loyalty sworn after Hindenburg's death.",
      "origin": "German literary allusion to an English folk saying; popularised by Goebbels's propaganda."
    },
    {
      "term": "Nuremberg Laws",
      "definition": "Two antisemitic laws enacted at the Nuremberg party rally on 15 September 1935: (1) the Reich Citizenship Law (Reichsbürgergesetz), stripping Jews of German citizenship; (2) the Law for the Protection of German Blood and Honour (Gesetz zum Schutze des deutschen Blutes und der deutschen Ehre), forbidding marriage and sexual relations between Jews and non-Jews. Supplementary decrees defined who counted as a Jew (one Jewish grandparent sufficient in some cases). The laws provided the legal basis for progressive economic and social exclusion.",
      "origin": "Named for Nuremberg, where the annual NSDAP congress was held."
    },
    {
      "term": "Ordensburg",
      "definition": "Literally 'Order Castle'. Three elite training schools for NSDAP political leaders: Vogelsang (Eifel), Sonthofen (Allgäu), and Krössinsee (Pomerania). Named after medieval Teutonic Order castles, they provided political and physical training for the future Nazi leadership elite, selected from the Hitler Youth. The Ordensburgen were among the most lavishly funded party projects; graduates were intended to form the leadership cadre of the coming Thousand-Year Reich.",
      "origin": "German: Orden (order, as in military/religious order) + Burg (castle, fortress)"
    },
    {
      "term": "Reichstag",
      "definition": "The German parliament building and legislative body. After the February 1933 fire and the Enabling Act, the Reichstag retained only ceremonial functions, meeting occasionally to hear Hitler's speeches or to rubber-stamp major announcements. The building itself was not repaired; sessions were held in the Kroll Opera House across the square. After 1942 the Reichstag did not meet at all.",
      "origin": "German: Reich (empire, realm) + Tag (day, as in assembly day)"
    },
    {
      "term": "SA (Sturmabteilung)",
      "definition": "Literally 'Storm Detachment'. The NSDAP's original paramilitary wing, known as 'Brownshirts' for their uniform. Founded 1921, the SA used violence to disrupt political meetings, intimidate opponents, and attack Jews. At its peak (1934) it had 4.5 million members — by far the largest military force in Germany. Its political ambitions under Ernst Röhm (absorbing the Wehrmacht) led to the Night of the Long Knives (1934), after which it became a ceremonial organisation of no political significance.",
      "origin": "German: Sturm (storm, assault) + Abteilung (detachment, unit)"
    },
    {
      "term": "SS (Schutzstaffel)",
      "definition": "Literally 'Protection Squadron'. Founded 1925 as Hitler's personal bodyguard (9 members); grown to a million-man empire under Heinrich Himmler by 1944. The SS was the ideological and operational vanguard of the Nazi racial state: it ran the concentration and extermination camps, controlled the Gestapo, deployed the Einsatzgruppen, fielded the Waffen-SS military force, and administered occupied territories. Declared a criminal organisation at Nuremberg.",
      "origin": "German: Schutz (protection) + Staffel (squadron, echelon)"
    },
    {
      "term": "Volksgemeinschaft",
      "definition": "Literally 'people's community'. The Nazi concept of a racially homogeneous German national community bound by blood and soil, from which Jews, Roma, disabled persons, homosexuals, and political opponents were systematically excluded. It was also a mobilising ideal promising to overcome class divisions through racial solidarity — an appeal that resonated with many during the Depression. In practice, its enforcement required surveillance, informants, and terror.",
      "origin": "German: Volk (people, folk) + Gemeinschaft (community)"
    },
    {
      "term": "Waffen-SS",
      "definition": "The armed wing of the SS that served alongside the Wehrmacht during the war. Formed from SS-VT (Special Purpose Troops, 1933) and SS-Totenkopfverbände (Death's Head Units, who guarded camps). By 1945 comprised 38 divisions totalling nearly 900,000 men from Germany and occupied/allied nations across Europe. Elite Waffen-SS units (Leibstandarte, Das Reich, Totenkopf) fought with distinction by military standards while committing documented war crimes including the Malmedy massacre and the massacre at Oradour-sur-Glane.",
      "origin": "German: Waffen (weapons, armed) + SS"
    },
    {
      "term": "Wehrmacht",
      "definition": "The unified armed forces of Nazi Germany (1935–1945), comprising the Heer (army), Kriegsmarine (navy), and Luftwaffe (air force), with the SS as a parallel military force. The term replaced the earlier Reichswehr. At its peak the Wehrmacht fielded over 9 million men. The Wehrmacht's complicity in war crimes on the Eastern Front — particularly regarding Soviet POWs (3.3 million died in captivity) and civilian reprisals — has been extensively documented by historians.",
      "origin": "German: Wehr (defence, protection) + Macht (power, force)"
    }
  ]
}

hitler\\chancellorship.json:
{
  "id": "hitler-chancellorship",
  "title": "The Chancellorship: Consolidation of Power 1933–1939",
  "summary": "The six years between Hitler's appointment as Chancellor and the outbreak of war constituted the most rapid destruction of a constitutional state in modern history.",
  "sections": [
    {
      "heading": "Appointment and Initial Cabinet, January 1933",
      "text": "On 30 January 1933, President Paul von Hindenburg appointed Hitler Chancellor of a coalition cabinet in which the NSDAP held only three of eleven positions — Hitler as Chancellor, Frick as Interior Minister, and Göring as Minister Without Portfolio. Hindenburg and his adviser Franz von Papen believed Hitler could be 'contained' and used as a political tool by the conservative establishment. This assessment proved catastrophically wrong within months. Hitler moved immediately to exploit his constitutional position, calling new elections and using the emergency powers latent in the Weimar constitution."
    },
    {
      "heading": "The Reichstag Fire and the Emergency Decrees, February–March 1933",
      "text": "On the night of 27–28 February 1933, the Reichstag building was set ablaze. A Dutch communist, Marinus van der Lubbe, was arrested at the scene and executed for the crime. Whether the Nazis engineered the fire, allowed it to happen, or merely exploited van der Lubbe's genuinely solitary action remains historically debated; the German communist party showed no foreknowledge. What is certain is the Nazi response: within 24 hours, Hindenburg signed the Reichstag Fire Decree (Verordnung des Reichspräsidenten zum Schutz von Volk und Staat), which suspended the fundamental civil liberties guaranteed by the Weimar constitution — freedom of speech, press, assembly, and privacy of communications. The decree was never repealed. It formed the legal framework for the terror that followed."
    },
    {
      "heading": "The Enabling Act: End of Parliamentary Democracy, March 1933",
      "text": "In the elections of 5 March 1933, held under conditions of SA intimidation and the suspension of civil liberties, the NSDAP won 43.9% of the vote — a plurality but not a majority. To secure the two-thirds majority needed for constitutional amendment, Hitler needed the Centre Party and other smaller parties. By promising to respect the Concordat with the Catholic Church and other assurances (not honoured), he secured their votes. On 23 March 1933, the Reichstag passed the Enabling Act (Ermächtigungsgesetz) by 444 votes to 94 — only the Social Democrats voted against; the Communist deputies had already been arrested or fled. The Act gave Hitler's cabinet full legislative authority for four years, bypassing both the Reichstag and President Hindenburg. Parliamentary democracy in Germany was over."
    },
    {
      "heading": "Gleichschaltung: Coordination of German Society, 1933–1934",
      "text": "The term Gleichschaltung — 'coordination' or 'bringing into line' — describes the process by which the Nazis systematically brought all institutions of German life under party control. Trade unions were dissolved in May 1933 and replaced by the Deutsche Arbeitsfront. Political parties were banned — first the SPD and KPD, then the centre-right parties dissolved themselves under pressure. A law of 14 July 1933 made the NSDAP the sole legal political party. State parliaments were dissolved and replaced by Reich governors. The civil service, judiciary, media, and cultural life were purged of Jews and political opponents by the Law for the Restoration of the Professional Civil Service (April 1933). By the end of 1933, no independent institutional counterweight to the Nazi party remained."
    },
    {
      "heading": "The Night of the Long Knives and the Death of Hindenburg, 1934",
      "text": "Ernst Röhm, the SA commander, was pushing for a 'second revolution' — absorbing the Wehrmacht into an SA-dominated 'people's army'. This alarmed both the military, whose professional status would be threatened, and Hitler's conservative allies, who feared social radicalism. Between 30 June and 2 July 1934 — the Night of the Long Knives — the SS and Gestapo murdered at least 85 people, including Röhm, former Chancellor Schleicher, and various other perceived threats. The killings were subsequently legalised retroactively. On 2 August 1934, Hindenburg died. Within hours, Hitler merged the offices of Chancellor and President, creating the title Führer und Reichskanzler. The Wehrmacht swore a personal oath of loyalty to Hitler by name — a decision that would bind the officer corps throughout the war."
    },
    {
      "heading": "Rearmament and the Four-Year Plan",
      "text": "In contravention of the Treaty of Versailles, Germany began open rearmament in March 1935 with the announcement of conscription and the re-established Luftwaffe. The Anglo-German Naval Agreement of June 1935 gave the expansion partial international legitimacy. In 1936, Hitler appointed Göring to direct the Four-Year Plan, an economic programme designed to make Germany self-sufficient in war materials within four years. Industrial output was reoriented toward armaments; consumer goods production was deliberately suppressed. By 1938, Germany was spending 17% of GNP on military expenditure — a level unsustainable without eventual expansion and plunder."
    },
    {
      "heading": "Territorial Expansion Without War, 1936–1939",
      "text": "Hitler's foreign policy in the pre-war years produced successive triumphs: the remilitarisation of the Rhineland (March 1936), unopposed; the Anschluss with Austria (March 1938), unopposed; the Sudetenland crisis resolved in Germany's favour at Munich (September 1938), with British and French consent; and the occupation of rump Czechoslovakia (March 1939), which Britain and France protested but did not resist. Each success reinforced Hitler's conviction that the Western powers lacked the will to fight, and that his own intuition — repeatedly vindicated over his generals' caution — was infallible. The destruction of Czechoslovakia was the point at which British policy finally hardened: Chamberlain's government extended military guarantees to Poland in March 1939."
    },
    {
      "heading": "Persecution of Jews: The Legal Phase, 1933–1938",
      "text": "In the period before the war, antisemitic persecution was pursued principally through legal and economic means. The April 1933 boycott of Jewish businesses was followed by the Law for the Restoration of the Professional Civil Service (expelling Jews from public employment), the Nuremberg Laws (September 1935, stripping Jews of citizenship and prohibiting Jewish-German marriage), and progressive exclusion from professions, universities, and public life. The November 1938 Kristallnacht pogrom — during which over 7,500 Jewish businesses were destroyed, 1,400 synagogues burned, and 30,000 Jews arrested and sent to camps — marked the shift toward outright physical violence. The proceeds of the pogrom were effectively stolen by the state: Jews were required to pay a 1-billion-Reichsmark 'atonement fine' for the damage done to their own property."
    }
  ],
  "sources": [
    { "ref": "Evans, Richard J. The Third Reich in Power. Penguin Press, 2005." },
    { "ref": "Kershaw, Ian. Hitler: 1889–1936 Hubris. W.W. Norton, 1998. Chapters 12–16." },
    { "ref": "Gellately, Robert. Backing Hitler: Consent and Coercion in Nazi Germany. Oxford University Press, 2001." },
    { "ref": "Burleigh, Michael. The Third Reich: A New History. Hill and Wang, 2000." },
    { "ref": "Bundesarchiv Berlin-Lichterfelde: R43II (Reich Chancellery files)." }
  ]
}

hitler\\end.json:
{
  "id": "hitler-end",
  "title": "The Fall of the Third Reich and Hitler's Death",
  "dates": { "start": "1944-07-20", "end": "1945-04-30" },
  "sections": [
    { "heading": "The Failed Assassination, July 1944", "text": "Colonel Claus von Stauffenberg's bomb at Rastenburg on 20 July 1944 failed to kill Hitler. The attempt triggered brutal reprisals: approximately 7,000 arrested, nearly 5,000 executed, including senior military figures. Field Marshal Rommel was forced to commit suicide." },
    { "heading": "Retreat and Collapse, 1944–1945", "text": "By late 1944 Germany faced catastrophic defeat on all fronts. The failure of the Ardennes offensive (December 1944) exhausted the last reserves. Soviet forces crossed the Vistula in January 1945; American and British forces crossed the Rhine in March. Hitler rejected all advice to negotiate or withdraw to a defensible position." },
    { "heading": "The Berlin Bunker", "text": "Hitler moved to the Führerbunker beneath the Reich Chancellery garden in January 1945. On 16 April Soviet forces began their final assault on Berlin. Hitler refused to leave; he expected 'Army Detachment Steiner' to counterattack and relieve the city — Steiner had no forces to do so. On 22 April, Hitler learned the truth and acknowledged Germany had lost the war." },
    { "heading": "Death, 30 April 1945", "text": "On 29 April 1945, Hitler married Eva Braun in a brief ceremony in the bunker. He dictated his political testament — blaming the Jews for the war and urging Germany to continue racial struggle — and his personal will. At approximately 3:30 PM on 30 April 1945, Hitler shot himself. Eva Braun took poison simultaneously. Their bodies were burned in the Chancellery garden per Hitler's instructions. Germany surrendered unconditionally on 8 May 1945." }
  ]
}

hitler\\family.json:
{
  "id": "hitler-family",
  "title": "Family Background and Personal Life",
  "summary": "Hitler's family origins, personal relationships, and private life — documented from archival records and contemporary testimony.",
  "sections": [
    {
      "heading": "Paternal Line: The Schicklgruber Origins",
      "text": "Hitler's father, Alois, was born on 7 June 1837 in Strones, Lower Austria, and was registered as illegitimate under the name Alois Schicklgruber. His mother, Maria Schicklgruber, had worked as a cook in the household of a Jewish family named Frankenberger in Graz — a circumstance later exploited by wartime propagandists and contested by historians. The identity of Alois's father remains uncertain; the most credible candidate is Johann Georg Hiedler, whom Maria later married in 1842. In 1877, Alois formally changed his surname to Hitler (a variant of Hiedler), the name his son Adolf would carry to infamy."
    },
    {
      "heading": "Alois Hitler: Father",
      "text": "Alois Hitler (1837–1903) was a customs official (Zollbeamter) who rose through the Austrian civil service to a respectable middle-class position. He was ambitious, authoritarian, and reputedly harsh with his children. He married three times: first to Anna Glasl-Hörer (d. 1883), then to Franziska (Fanni) Matzelsberger (d. 1884), and finally to his niece Klara Pölzl in 1885. Klara was twenty-three years younger than Alois. By his first two marriages he had two children: Alois Jr. and Angela. Alois Sr. died of a pleural haemorrhage on 3 January 1903 in Leonding while drinking his morning wine at the local inn. Adolf was thirteen years old."
    },
    {
      "heading": "Klara Pölzl: Mother",
      "text": "Klara Hitler née Pölzl (1860–1907) was by all accounts a gentle, devoted woman who doted on Adolf, her only surviving child of five. (Of six children, three died in infancy; a fourth, Edmund, died aged six in 1900.) She had grown up as a ward in the Alois Hitler household and was his second cousin once removed; the couple required a Papal dispensation to marry. Klara developed breast cancer in 1906 and died on 21 December 1907. Hitler later described her death as the greatest loss of his life. A physician named Dr. Eduard Bloch — a Jewish doctor who treated her — was treated with rare personal courtesy by Hitler years later; he was permitted to emigrate to the United States in 1940 with his possessions intact. The case is one of the few recorded instances of personal gratitude overriding Hitler's antisemitism."
    },
    {
      "heading": "Siblings",
      "text": "Adolf had one full sibling who survived to adulthood: Paula Hitler (1896–1960), six years his junior. Paula led an obscure life in Vienna, working as a secretary under the name Wolff to conceal her identity. She met with her brother only occasionally during the Third Reich years; Hitler provided her a pension but kept her at a distance. She never married and outlived the war by fifteen years, dying in Berchtesgaden in 1960. His half-sister Angela Raubal (née Hitler, 1883–1949), daughter of Alois by his second wife, was closer to Adolf during the Weimar years. Her daughter Geli Raubal lived in Hitler's Munich apartment and died there in September 1931 — a death officially ruled suicide by gunshot."
    },
    {
      "heading": "Geli Raubal: The Central Personal Tragedy",
      "text": "Angela Maria (Geli) Raubal (1908–1931), Hitler's niece, moved to Munich in 1929 to study medicine. She lived in Hitler's apartment on Prinzregentenplatz. Contemporary witnesses and later historians suggest Hitler was obsessively attached to her; the precise nature of the relationship remains disputed. Geli died on 19 September 1931 from a gunshot wound to the chest, from Hitler's pistol, in his apartment. The police ruled her death a suicide; her mother accepted this verdict. Hitler was in Hamburg at the time of the shot. He returned immediately to Munich and was reportedly inconsolable. Geli's room at the Berghof was preserved as a shrine until the end of the war. Several biographers — including Ian Kershaw — consider her death the single event that most darkened Hitler's private psychology."
    },
    {
      "heading": "Eva Braun: Companion and Final Wife",
      "text": "Eva Braun (1912–1945) was born in Munich and worked as a photographic assistant for Heinrich Hoffmann, Hitler's official photographer, where she met Hitler in 1929. Their relationship remained almost entirely hidden from the German public throughout the Third Reich years; she was kept from official functions and was largely unknown as his companion. She made two suicide attempts in the early years of their relationship, in 1932 and 1935. Eva lived at the Berghof retreat in Bavaria and was described by those who knew her as cheerful, athletic, and politically uncurious — interested in fashion, photography, and films. Hitler married Eva Braun on 29 April 1945, in a civil ceremony in the Führerbunker, less than 40 hours before both committed suicide. Eva Braun took cyanide on 30 April 1945; Hitler shot himself simultaneously. Their bodies were burned in the Reich Chancellery garden."
    },
    {
      "heading": "Nephews and Nieces in Britain and America",
      "text": "William Patrick Hitler (1911–1987), son of Hitler's half-brother Alois Jr., was born in Liverpool, England. He emigrated to the United States in 1939 and after several attempts to leverage his family name for financial benefit, enlisted in the US Navy in 1944, serving until 1947. He petitioned Hitler — unsuccessfully — for a better position in Germany in the 1930s. He subsequently settled on Long Island under the name William Stuart-Houston. He had four sons, all of whom reportedly agreed not to have children, ending this branch of the family line."
    }
  ],
  "sources": [
    { "ref": "Kershaw, Ian. Hitler: 1889–1936 Hubris. W.W. Norton, 1998. Chapters 1–2." },
    { "ref": "Toland, John. Adolf Hitler. Doubleday, 1976." },
    { "ref": "Hamann, Brigitte. Hitler's Vienna: A Dictator's Apprenticeship. Oxford University Press, 1999." },
    { "ref": "Bloch, Eduard. 'My Patient Hitler.' Collier's Weekly, 15 March 1941." }
  ]
}

hitler\\rise.json:
{
  "id": "hitler-rise",
  "title": "Hitler's Rise to Power, 1919–1933",
  "summary": "Hitler's rise from obscure political agitator to Chancellor of Germany in fourteen years is one of history's most studied examples of democratic collapse.",
  "sections": [
    {
      "heading": "Munich, 1919–1923",
      "text": "Hitler joined the tiny DAP in September 1919 and rapidly took control, transforming it into the NSDAP. His oratorical gifts drew thousands to his speeches. The failed Beer Hall Putsch of November 1923 resulted in his trial and imprisonment, during which he dictated Mein Kampf — turning a tactical defeat into a propaganda victory."
    },
    {
      "heading": "The Legal Path, 1925–1929",
      "text": "Released from prison in December 1924, Hitler rebuilt the NSDAP and committed to achieving power through elections rather than revolution. The party remained a fringe movement through the late 1920s, winning only 2.6% of the vote in May 1928."
    },
    {
      "heading": "Depression and Breakthrough, 1929–1932",
      "text": "The Great Depression transformed the political landscape. Unemployment reaching 6 million in 1932 destroyed faith in the Weimar system. NSDAP support surged: 18.3% in September 1930, 37.4% in July 1932 — making it Germany's largest party. Goebbels's propaganda machine, mass rallies, and the SA's intimidation tactics combined with genuine popular appeal."
    },
    {
      "heading": "Appointment as Chancellor, 30 January 1933",
      "text": "NSDAP support actually fell slightly to 33.1% in November 1932. Franz von Papen convinced President Hindenburg that appointing Hitler Chancellor in a conservative cabinet would allow them to control him. Hitler was appointed Chancellor on 30 January 1933. Within months, the Reichstag Fire, the Enabling Act, and the elimination of all competing parties had transformed Germany into a dictatorship."
    }
  ]
}

hitler\\rule.json:
{
  "id": "hitler-rule",
  "title": "Hitler's Rule, 1933–1945",
  "sections": [
    { "heading": "Consolidation of Power, 1933–1934", "text": "After becoming Chancellor, Hitler moved rapidly to dismantle Weimar democracy. The Reichstag Fire Decree (28 Feb 1933) suspended civil liberties; the Enabling Act (23 March 1933) gave the cabinet legislative power; trade unions were dissolved (May 1933); all other parties were banned (July 1933). The Night of the Long Knives (30 June 1934) eliminated the SA leadership. When Hindenburg died (2 August 1934), Hitler merged the offices of Chancellor and President." },
    { "heading": "Economic Policy and Rearmament", "text": "Hitler appointed Hjalmar Schacht as Economics Minister. A massive public works and rearmament programme reduced unemployment from 6 million to 300,000 by 1938 — though achieved through deficit spending and autarky that made Germany economically dependent on continued expansion. Rearmament violated the Versailles Treaty openly from 1935." },
    { "heading": "Foreign Policy and Expansion, 1936–1939", "text": "A series of diplomatic coups — Rhineland remilitarisation (1936), Anschluss with Austria (1938), annexation of the Sudetenland (Munich Agreement, 1938), occupation of Czechoslovakia (1939) — were achieved without war. Hitler correctly judged that France and Britain would not fight. The invasion of Poland in September 1939 finally triggered the war he had long sought but on a timetable and with enemies he had not intended." },
    { "heading": "Wartime Leadership, 1939–1945", "text": "Initially brilliant — France fell in six weeks, most of Europe was conquered — Hitler's strategic intuition increasingly failed from 1941. His decision to invade the Soviet Union, declare war on the United States, interfere personally in military decisions, and refuse strategic withdrawals led to a series of catastrophes: Stalingrad, the loss of North Africa, Normandy, and the encirclement of Germany on all fronts. He remained in the Berlin bunker as Soviet forces entered the city, marrying Eva Braun on 29 April 1945 and dictating a final testament blaming the Jews for the war before shooting himself on 30 April." }
  ]
}

hitler\\wartime.json:
{
  "id": "hitler-wartime",
  "title": "Hitler as War Leader 1939–1945",
  "summary": "Hitler's direction of the Second World War — his strategic decisions, command style, and the progressive military and moral catastrophe they produced.",
  "sections": [
    {
      "heading": "The Decision for War",
      "text": "Hitler had determined by late 1937 that war was necessary for Germany's expansion — this is documented in the Hossbach Memorandum of 5 November 1937, which recorded his strategic vision: Germany must secure Lebensraum by force by 1943–1945 at the latest. The invasion of Poland (1 September 1939) was preceded by the false-flag Gleiwitz incident to provide a pretext. Hitler had expected Britain and France to remain passive as they had at Munich; when they declared war on 3 September, he was genuinely surprised, reportedly asking Ribbentrop: 'What now?' Despite the miscalculation, the Polish campaign was over in five weeks. The Soviet invasion from the east on 17 September sealed Poland's fate."
    },
    {
      "heading": "The Western Campaign and Its Lessons, 1940",
      "text": "The German victory in France in May–June 1940 appeared to vindicate Hitler's strategic instincts against his generals' caution. The Manstein Plan — a drive through the Ardennes to cut off Allied forces in Belgium — had originally been proposed over the objections of OKH (army high command); Hitler embraced it against the conventional advice. France fell in 46 days. Britain, however, refused to negotiate, and the Luftwaffe failed to achieve the aerial superiority needed for Operation Sea Lion (the planned invasion). Hitler ordered the indefinite postponement of Sea Lion in September 1940. Rather than resolving the British problem, he turned east."
    },
    {
      "heading": "Operation Barbarossa: The Ideological War, 1941",
      "text": "The invasion of the Soviet Union (22 June 1941) was not merely a military campaign but an ideological one. Hitler's Commissar Order directed that captured Soviet political officers be shot immediately rather than taken prisoner. The Barbarossa Jurisdiction Decree suspended military legal protections for occupied Soviet territory. These orders, issued before the invasion, transformed the war in the east into a war of extermination from its opening day. Initial German advances were enormous: by October 1941, three million Soviet troops had been killed or captured in encirclement battles. But the failure to capture Moscow before winter — Operation Typhoon stalled in the mud and snow of November–December — ended the prospect of a decisive single-campaign victory."
    },
    {
      "heading": "Command Conflicts and the 'Hold Order' Doctrine",
      "text": "The winter crisis of 1941–1942 on the Eastern Front produced the first major command rupture between Hitler and his generals. When Army Group Centre's overextended positions began to collapse under Soviet counterattacks, generals recommended tactical withdrawal. Hitler refused, issuing his famous 'stand fast' order: divisions were to hold their positions regardless of tactical situation. The order worked — the front stabilised — and it convinced Hitler that his own instinct for rigid defence was superior to his generals' willingness to withdraw. This doctrine, applied increasingly inflexibly through 1943–1945, would eventually trap and destroy entire field armies."
    },
    {
      "heading": "1942: Overextension and Stalingrad",
      "text": "The 1942 summer offensive (Case Blue) divided Army Group South to drive simultaneously toward the Caucasus oilfields and the Volga. When 6th Army reached Stalingrad in August 1942, Hitler became fixated on capturing the city — named for his adversary — beyond strategic logic. He refused requests to withdraw when Soviet forces encircled the 6th Army in November 1942 (Operation Uranus). Göring's assurance that the Luftwaffe could supply 6th Army by air was false; the army starved. On 2 February 1943, Field Marshal Paulus surrendered approximately 91,000 survivors. It was the decisive turning point of the Eastern Front."
    },
    {
      "heading": "Kursk, the Atlantic, and the Italian Collapse, 1943",
      "text": "The Battle of Kursk (July 1943) — the last major German strategic offensive in the east — was compromised before it began: the Soviets, informed by intelligence including the British Ultra programme, had prepared deep defensive positions. The German attack failed within days. Hitler called it off to redirect forces to Italy, where Allied landings had begun. Mussolini's overthrow on 25 July 1943 removed Germany's principal ally and opened a new front in southern Europe. Simultaneously, the Battle of the Atlantic was being lost: new Allied anti-submarine technology and tactics sank 41 U-boats in May 1943, forcing Grand Admiral Dönitz to withdraw submarines from the North Atlantic."
    },
    {
      "heading": "The Final Year: Absolute Authority and Total Defeat, 1944–1945",
      "text": "After the failed July 1944 assassination attempt, Hitler's grip on military command tightened and his health deteriorated visibly. The Ardennes offensive of December 1944 — Operation Wacht am Rhein — committed Germany's last strategic reserves in a failed attempt to split the Allied front and capture Antwerp. When it failed, there was nothing left. Hitler refused all suggestions of negotiation, declaring he would fight to the last. He dismissed or threatened generals who retreated without permission. His operational orders became increasingly divorced from reality — directing 'armies' that existed only on paper, ordering counterattacks by divisions that had ceased to exist. He died in the Führerbunker on 30 April 1945."
    },
    {
      "heading": "Hitler's Relationship with the Holocaust",
      "text": "Historical debate about the precise moment Hitler issued an explicit order for the extermination of European Jews has never been fully resolved — no written Führer order has been found. What is established is that the genocide developed from Hitler's expressed genocidal intentions (Mein Kampf, speeches, documented statements), the institutional apparatus he created (SS, Gestapo, Einsatzgruppen), and the escalating radicalism of his subordinates acting in what they understood to be his will. Göring's instruction to Heydrich of 31 July 1941 to prepare a 'total solution' (Gesamtlösung) followed six weeks of Einsatzgruppen mass shootings in the east. The Wannsee Conference of 20 January 1942 coordinated the industrial-scale murder that followed. Hitler received regular reports; his approval of deportations was documented in multiple instances."
    }
  ],
  "sources": [
    { "ref": "Kershaw, Ian. Hitler: 1936–1945 Nemesis. W.W. Norton, 2000." },
    { "ref": "Beevor, Antony. Stalingrad. Viking, 1998." },
    { "ref": "Glantz, David M. and House, Jonathan. When Titans Clashed. University Press of Kansas, 1995." },
    { "ref": "Browning, Christopher R. The Origins of the Final Solution. University of Nebraska Press, 2004." },
    { "ref": "Trevor-Roper, H.R. The Last Days of Hitler. Macmillan, 1947." },
    { "ref": "OKW War Diary (Kriegstagebuch des Oberkommando der Wehrmacht). Bundesarchiv-Militärarchiv, Freiburg." }
  ]
}

