party\\programme.json:
{
  "title": "The 25-Point Programme of the NSDAP",
  "announced": "24 February 1920",
  "location": "Hofbräuhaus, Munich",
  "context": "The 25-Point Programme was announced by Adolf Hitler at the first mass meeting of the German Workers' Party (renamed that day to the NSDAP). Written principally by Anton Drexler and Hitler with contributions from Gottfried Feder, it remained the official party programme throughout the Third Reich, declared 'unalterable' in 1926. In practice, many points were ignored, modified, or implemented selectively. It combined nationalist, antisemitic, corporatist, and proto-socialist demands in a deliberate attempt to appeal across class lines.",
  "points": [
    {
      "number": 1,
      "text": "We demand the unification of all Germans in a Great Germany on the basis of the right of national self-determination.",
      "analysis": "The foundational demand for Pan-German nationalism, providing ideological justification for the Anschluss (1938) and the annexation of the Sudetenland (1938)."
    },
    {
      "number": 2,
      "text": "We demand equality of rights for the German people in its dealings with other nations, and abolition of the peace treaties of Versailles and Saint-Germain.",
      "analysis": "A rejection of the post-WWI settlement, particularly reparations, territorial losses, and military restrictions — a universally popular demand in Weimar Germany across the political spectrum."
    },
    {
      "number": 3,
      "text": "We demand land and territory (colonies) for the maintenance of our people and the settlement of our surplus population.",
      "analysis": "The colonial demand — less about overseas territories than about the later doctrine of Lebensraum in Eastern Europe, developed more fully in Mein Kampf (1925)."
    },
    {
      "number": 4,
      "text": "Only members of the nation may be citizens of the State. Only those of German blood, whatever their creed, may be members of the nation. Accordingly, no Jew may be a member of the nation.",
      "analysis": "The central racial exclusion clause, providing the ideological basis for the Nuremberg Laws (1935) and all subsequent antisemitic legislation."
    },
    {
      "number": 5,
      "text": "Non-citizens are to be able to live in Germany only as guests and must be subject to laws for aliens.",
      "analysis": "Implemented through the Reich Citizenship Law (1935), which created a legal distinction between citizens (Reichsbürger) and state subjects (Staatsangehörige)."
    },
    {
      "number": 6,
      "text": "The right to vote on the State's government and legislation shall be enjoyed by the citizens of the State alone.",
      "analysis": "Served as justification for the removal of political rights from Jews and others defined as non-citizens."
    },
    {
      "number": 7,
      "text": "We demand that the State shall above all undertake to ensure that every citizen shall have the possibility of living decently and earning a livelihood.",
      "analysis": "A welfare-nationalist demand that formed part of the NSDAP's appeal to the unemployed during the Great Depression. Partially implemented through the DAF (German Labour Front) and NSV (People's Welfare organisation)."
    },
    {
      "number": 8,
      "text": "All further non-German immigration must be prevented. We demand that all non-Germans who entered Germany after 2 August 1914 be forced to leave the Reich immediately.",
      "analysis": "Anti-immigration provision targeting particularly Eastern European Jews (Ostjuden) who had arrived in Germany during and after WWI."
    },
    {
      "number": 13,
      "text": "We demand the nationalisation of all businesses which have been formed into corporations (trusts).",
      "analysis": "The most explicitly socialist-sounding clause; largely ignored after 1933 as the Nazi regime maintained and worked with large private industry. Heavy industrialists who had supported the party were not nationalised."
    },
    {
      "number": 17,
      "text": "We demand a land reform suitable to our national requirements, the passing of a law for the expropriation of land for communal purposes without compensation, abolition of interest on land loans, and prevention of all speculation in land.",
      "analysis": "Another clause reflecting the programme's appeal to rural voters; added a note in 1928 clarifying it applied only to 'Jewish companies formed for speculative purposes', illustrating how antisemitic intent could reframe apparently socialist demands."
    },
    {
      "number": 24,
      "text": "We demand freedom of religion for all religious denominations within the State so long as they do not endanger its existence or oppose the moral senses of the Germanic race. The Party as such advocates the standpoint of a positive Christianity without binding itself confessionally to any particular denomination.",
      "analysis": "The famous 'Positive Christianity' clause. Deliberately vague, it allowed the NSDAP to appeal to both Protestant and Catholic voters while avoiding commitment to either church. In practice, 'Positive Christianity' came to mean Christianity stripped of its Jewish origins and remade as a Germanic faith — a project pursued inconsistently and ultimately abandoned."
    },
    {
      "number": 25,
      "text": "For the execution of all of this, we demand the creation of a strong central power of the Reich. Unlimited authority of the central parliament over the whole Reich and its organisations in general.",
      "analysis": "The authoritarian constitutional demand, which in practice was implemented by abolishing the federal structure of the Weimar Republic and centralising power in the Reich Chancellery."
    }
  ],
  "declaration_of_immutability": "At the party congress of 22 May 1926, Hitler declared the programme 'unalterable'. This prevented factional debate over specific points but also meant the programme was never updated to reflect the evolving priorities of the regime. By 1933, the NSDAP had effectively ceased to function as a party programme document and had become a historical artefact of the party's founding.",
  "sources": [
    { "ref": "NSDAP. Das Programm der N.S.D.A.P. Munich, 1920. (Original German text.)" },
    { "ref": "Noakes, J. and Pridham, G. (eds). Nazism 1919–1945, Vol. 1: The Rise to Power. University of Exeter Press, 1998. Document 4." },
    { "ref": "Orlow, Dietrich. The History of the Nazi Party: 1919–1933. University of Pittsburgh Press, 1969." },
    { "ref": "Feder, Gottfried. Das Programm der NSDAP und seine weltanschaulichen Grundlagen. Munich: NSDAP, 1927." }
  ]
}

party\\religion.json:
{
  "title": "Religion, the Churches, and Positive Christianity",
  "summary": "The Nazi regime's relationship with Christianity was one of calculated ambiguity, tactical concession, and progressive hostility — driven by ideological incompatibility between Christian universalism and Nazi racial doctrine.",
  "sections": [
    {
      "heading": "Positive Christianity: The Programme Clause",
      "text": "Point 24 of the 1920 NSDAP programme called for 'positive Christianity' — a deliberately undefined term intended to secure the support of Germany's overwhelmingly Christian population while committing the party to nothing doctrinally specific. In Nazi usage, 'positive Christianity' generally meant Christianity purged of its Jewish origins (the Old Testament was particularly targeted), reinterpreted as a Germanic faith emphasising heroism, sacrifice, and racial solidarity rather than humility, sin, and universalism. It was never given consistent institutional form. Hitler personally expressed private contempt for Christianity in his Table Talk and other recorded conversations, describing it as suited only to 'weak people'."
    },
    {
      "heading": "The Reich Concordat with the Vatican, July 1933",
      "text": "On 20 July 1933, Hitler's government signed a Reichskonkordat with the Holy See — the most important international agreement the new regime concluded in its first year. The Concordat guaranteed the freedom of Catholic institutions and the rights of the Catholic Church in Germany; in return, the Vatican agreed that Catholic clergy would refrain from political activity, and dissolved the Catholic Centre Party (which had already dissolved itself under pressure). Pope Pius XI had serious reservations but accepted the agreement as the best available protection for German Catholics. Hitler regarded the Concordat as a major diplomatic success and an implicit international legitimation of his government. The Concordat's provisions were immediately and systematically violated by the regime."
    },
    {
      "heading": "The German Christians and the Reich Church",
      "text": "Within German Protestantism, the 'German Christians' (Deutsche Christen) were a pro-Nazi faction that sought to 'synchronise' the Protestant churches with National Socialist ideology. They won elections in Protestant church councils in July 1933 and supported the appointment of Ludwig Müller as Reich Bishop. The German Christians sought to remove the Old Testament from Christian scripture, deny Jesus's Jewish heritage, and apply the Aryan paragraph (excluding Jewish converts) to church offices. Their theology was rejected by a significant part of German Protestantism, leading to the formation of the opposing Confessing Church (Bekennende Kirche) in 1934."
    },
    {
      "heading": "The Confessing Church and Resistance",
      "text": "The Confessing Church (Bekennende Kirche), formed at the Barmen Synod of May 1934, rejected the German Christians' theological innovations and the subordination of the church to the state. Its founding declaration — the Barmen Declaration, drafted principally by theologian Karl Barth — insisted that the church was bound only to Christ, not to any political authority. Key figures included Martin Niemöller (U-boat commander turned pastor, arrested in 1937 and sent to Dachau), Dietrich Bonhoeffer (arrested in 1943 for his role in the military resistance, executed April 1945), and Bishop Theophil Wurm of Württemberg. The Confessing Church was not a resistance movement in the political sense — it objected primarily to state control of the church rather than Nazi ideology broadly — but it represented the most organised institutional opposition to regime encroachments."
    },
    {
      "heading": "The Mit Brennender Sorge Encyclical, March 1937",
      "text": "On 21 March 1937, Pope Pius XI issued the encyclical Mit Brennender Sorge ('With Burning Anxiety'), written in German and secretly distributed to German Catholic churches for simultaneous reading from pulpits on Palm Sunday. It condemned the violation of the 1933 Concordat, the deification of race and nation, and the substitution of a 'national god' for the God of Christian faith — though it did not explicitly name Hitler or the NSDAP. The Gestapo worked frantically to confiscate copies; the Sunday reading nonetheless reached millions of German Catholics. The regime's response was escalated harassment of the Catholic Church, including criminal prosecutions of priests on fabricated currency and morality charges."
    },
    {
      "heading": "The SS and Neo-Pagan Ideology",
      "text": "The SS under Heinrich Himmler developed the most systematic attempt to replace Christianity with a Germanic neo-pagan worldview. Himmler was fascinated by Nordic mythology, runic symbolism, and the supposed spiritual heritage of the ancient Germanic peoples. The SS developed its own lifecycle ceremonies (birth, marriage, death) to replace church sacraments, and its own calendar of 'Germanic' seasonal celebrations to replace Christian festivals. The Externsteine rock formation in Teutoburg Forest was identified as a sacred Germanic site and subjected to pseudo-archaeological investigation. Himmler's SS castle at Wewelsburg in Westphalia was designed as the symbolic centre of an SS order with quasi-religious pretensions. These projects remained largely on the fringes of the regime; the German population remained overwhelmingly Christian in practice."
    },
    {
      "heading": "Euthanasia and Church Protest",
      "text": "The T4 euthanasia programme — the systematic murder of disabled Germans deemed 'lives unworthy of life' — generated the most successful public protest the churches mounted against any Nazi programme. Beginning in 1939 and officially suspended in August 1941, T4 killed approximately 70,000 people in six killing centres using carbon monoxide gas. Bishop Clemens von Galen of Münster delivered three sermons in August 1941 openly denouncing the programme, calling it murder. Copies circulated throughout Germany and were dropped by RAF aircraft over the Reich. The Gestapo considered arresting von Galen but feared it would alienate the Catholic population of Westphalia; Hitler was reportedly furious but deferred action. T4 was officially suspended — though it continued covertly — partly in response to the protest."
    }
  ],
  "sources": [
    { "ref": "Burleigh, Michael. The Third Reich: A New History. Hill and Wang, 2000. Chapter 5." },
    { "ref": "Matheson, Peter. The Third Reich and the Christian Churches. T&T Clark, 1981." },
    { "ref": "Kershaw, Ian. The Nazi Dictatorship: Problems and Perspectives of Interpretation (4th ed.). Arnold, 2000." },
    { "ref": "Scholder, Klaus. The Churches and the Third Reich (2 vols). Fortress Press, 1987–88." },
    { "ref": "Steigmann-Gall, Richard. The Holy Reich: Nazi Conceptions of Christianity. Cambridge University Press, 2003." }
  ]
}

party\\state-relations.json:
{
  "title": "Party–State Relations in the Third Reich",
  "description": "The relationship between the NSDAP and the German state apparatus.",
  "content": "The Third Reich was characterised by a complex, sometimes chaotic overlapping of party and state structures. Hitler deliberately maintained competing agencies with ambiguous jurisdictions — a system scholars call 'institutional Darwinism' — in which subordinates competed for his favour rather than cooperating through clear command structures.\n\nInitially, the state bureaucracy (inherited from Weimar) continued to function under Nazi political supervision. Over time, party structures increasingly paralleled, competed with, and ultimately superseded state institutions. The SS under Himmler grew to represent a second state entirely, with its own military (Waffen-SS), police (Gestapo, SD), economic enterprises (SS businesses), and administrative apparatus in occupied territories.\n\nGauleiter served simultaneously as Reich Governors (Reichsstatthalter), blending party and state authority at the regional level. The result was administrative confusion that, paradoxically, left Hitler as the indispensable arbiter — reinforcing his personal authority while simultaneously producing inefficiencies that hampered the war effort."
}

party\\structure.json:
{
  "title": "Structure of the NSDAP",
  "description": "The NSDAP was organised as a highly centralised party with the Führer at its apex. The party structure paralleled and ultimately superseded the German state apparatus.",
  "hierarchy": [
    {
      "level": "Führer",
      "description": "Adolf Hitler. Held absolute authority over the party. After 1934, combined party leadership with the offices of Chancellor and President."
    },
    {
      "level": "Reichsleitung (Reich Leadership)",
      "description": "The central party apparatus in Munich. Consisted of Reichsleiters responsible for specific functions: propaganda (Goebbels), finance (Schwarz), party organisation (Ley), racial policy (Rosenberg)."
    },
    {
      "level": "Gauleiter (District Leaders)",
      "description": "Germany was divided into 43 Gaue (districts). Each Gauleiter was a regional party boss with considerable local authority, often serving simultaneously as Reichsstatthalter (Reich Governor) of their territory."
    },
    {
      "level": "Kreisleiter (County Leaders)",
      "description": "Each Gau was divided into Kreise (counties). Kreisleiter were responsible for party organisation and implementing directives at county level."
    },
    {
      "level": "Ortsgruppenleiter (Local Group Leaders)",
      "description": "The base level of the party organisation, covering villages and urban neighbourhoods. Responsible for surveillance, welfare distribution, and enforcing conformity."
    }
  ],
  "affiliated_organisations": [
    { "name": "Sturmabteilung (SA)", "role": "Original paramilitary wing, 'Brownshirts'. Subordinated after Night of the Long Knives (1934)." },
    { "name": "Schutzstaffel (SS)", "role": "Elite protective corps; grew into a state within a state under Heinrich Himmler. Controlled camps, Gestapo, Waffen-SS." },
    { "name": "Hitlerjugend (HJ)", "role": "Hitler Youth — mandatory membership for German boys aged 14-18." },
    { "name": "Bund Deutscher Mädel (BDM)", "role": "League of German Girls — female counterpart to HJ." },
    { "name": "Deutsche Arbeitsfront (DAF)", "role": "German Labour Front — replaced trade unions dissolved in 1933." },
    { "name": "Nationalsozialistische Volkswohlfahrt (NSV)", "role": "National Socialist People's Welfare — administered social welfare." }
  ]
}

